PlayerInitialConfig = {}
PlayerInitialConfig.Initial = {
    gun = {},
    prop = {},
    block = {},
    module = {},
    armor_value = 0
}

function PlayerInitialConfig:init(config)
    local item = {}
    item.rifle = config.rifle or 0
    item.pistol = config.pistol or 0
    item.closeIn = config.closeIn or 0
    item.snipe = config.snipe or 0
    item.bazooka = config.bazooka or 0
    item.prop = config.prop or {}
    item.block = config.block or {}
    item.module = config.module or {}
    self.Initial.armor_value = config.armor_value or 2

    self:addGun(item.rifle)
    self:addGun(item.pistol)
    self:addGun(item.closeIn)
    self:addGun(item.snipe)
    self:addGun(item.bazooka)
    self:addProp(item.prop)
    self:addBlock(item.block)
    self:addModule(item.module)
end

function PlayerInitialConfig:addGun(gunId)
    local gun = GunConfig:getGunByItemId(gunId)
    if gun ~= nil then
        self.Initial.gun[tostring(gun.gunType)] = {
            Id = gun.id,
            ItemId = gun.itemId,
            PropertyIds = gun.propertyIds,
            AddDamage = 0
        }
    end
end

function PlayerInitialConfig:addProp(props)
    for index, prop in pairs(props) do
        local item = PropConfig:getPropByItemId(tonumber(prop.id))
        if item ~= nil then
            table.insert(self.Initial.prop, {
                Id = item.propId,
                ItemId = item.itemId,
                PropertyIds = prop.propertyIds,
                AddValues = prop.addValues
            })
        end
    end
end

function PlayerInitialConfig:addBlock(blockConfig)
    local block = PropConfig:getPropByItemId(tonumber(blockConfig[1]))
    if block ~= nil then
        self.Initial.block["7"] = {
            Id = block.propId,
            ItemId = block.itemId,
            PropertyIds = blockConfig[2],
            Life = blockConfig[3],
            Count = blockConfig[4]
        }
    end
end

function PlayerInitialConfig:addModule(modules)
    for index, module in pairs(modules) do
        self.Initial.module[tostring(index)] = {
            Id = tonumber(module)
        }
    end
end

function PlayerInitialConfig:getInitialConfig()
    return self.Initial
end